  const defaultState=()=>({profile:{name:"",className:""},account:{studentCode:"",userId:"",cloud:false,resetVersion:0},view:"dashboard",nav:{module:"u1",lesson:0,tab:"overview",boss:false},lastPage:null,lastQuestion:null,activities:{},rewards:{},pointAwards:{},xp:0,coins:0,stars:0,badges:[],sound:true,updatedAt:Date.now()});
  function normalizeState(old){const base=defaultState(),safe=old&&typeof old==='object'?old:{},nav={...base.nav,...safe.nav};return {...base,...safe,view:safe.view||"dashboard",profile:{...base.profile,...safe.profile},account:{...base.account,...safe.account},nav,lastPage:safe.lastPage||{...nav},lastQuestion:safe.lastQuestion||null,activities:safe.activities||{},rewards:safe.rewards||{},pointAwards:safe.pointAwards||{},badges:Array.isArray(safe.badges)?safe.badges:[]}}
  function loadState(){try{const raw=localStorage.getItem(APP_KEY);return raw?normalizeState(JSON.parse(raw)):defaultState()}catch(e){return defaultState()}}
  function rememberAppOpen(open){try{if(open)localStorage.setItem(APP_OPEN_KEY,'1');else localStorage.removeItem(APP_OPEN_KEY)}catch(e){}}
  function wasAppOpen(){try{return localStorage.getItem(APP_OPEN_KEY)==='1'}catch(e){return false}}
  function loadAccessCache(studentCode){try{const code=String(studentCode||'').toUpperCase();if(!code)return {student:{},class:{},className:''};const raw=localStorage.getItem(ACCESS_CACHE_PREFIX+code);if(!raw)return {student:{},class:{},className:''};const saved=JSON.parse(raw);return {student:saved.student||{},class:saved.class||{},className:saved.className||''}}catch(error){return {student:{},class:{},className:''}}}
