  function easy(text){if(text===undefined||text===null)return '';return String(text).replace(EASY_RX,m=>{const r=EASY_MAP.get(m.toLowerCase())||m;return /^[A-Z]/.test(m)?r.charAt(0).toUpperCase()+r.slice(1):r}).replace(/;\s+/g,'. ').replace(/,\s+while\s+/gi,'. ').replace(/,\s+but\s+/gi,'. But ').replace(/,\s+so\s+/gi,'. So ').replace(/,\s+which\s+/gi,'. This ').replace(/,\s+where\s+/gi,'. There, ').replace(/(^|[.!?]\s+)([a-z])/g,(m,p,c)=>p+c.toUpperCase())}
