  function orderQuestion(sentence,seed){const words=sentence.replace(/[.!?]$/,'').split(/\s+/),end=/[.!?]$/.test(sentence)?sentence.slice(-1):'.';let wrong1=[...words].reverse().join(' ') + end,wrong2=[...words.slice(1),words[0]].join(' ') + end,wrong3=[...words];if(wrong3.length>2)[wrong3[0],wrong3[1]]=[wrong3[1],wrong3[0]];wrong3=wrong3.join(' ') + end;return {...optionQuestion('Choose the sentence in the correct order.',sentence,[wrong1,wrong2,wrong3],`Correct sentence: ${sentence}`,seed),type:'order'}}
  function lessonQuestions(lesson){if(window.ConnectPlusQuestionsV6WordCorrection)return window.ConnectPlusQuestionsV6WordCorrection.lessonQuestions(lesson);return (lesson.manual||[]).map((q,i)=>({...q,id:`${lesson.id}-fallback-q${i+1}`,sectionType:'choice',sectionTitle:'Choose',sectionInstruction:'Choose the correct answer.',indexInSection:i,sectionTotal:(lesson.manual||[]).length,sectionStartIndex:0,sectionEndIndex:(lesson.manual||[]).length-1}))}
  function bossQuestions(m){if(window.ConnectPlusQuestionsV6WordCorrection)return window.ConnectPlusQuestionsV6WordCorrection.bossQuestions(m);let all=[];m.lessons.forEach(l=>all.push(...lessonQuestions(l)));return deterministicShuffle(all,100+m.number).slice(0,50)}
