  function playTone(ok=true){if(!state.sound)return;try{const A=window.AudioContext||window.webkitAudioContext,ctx=new A(),osc=ctx.createOscillator(),gain=ctx.createGain();osc.connect(gain);gain.connect(ctx.destination);osc.type=ok?'sine':'triangle';osc.frequency.setValueAtTime(ok?620:180,ctx.currentTime);if(ok)osc.frequency.exponentialRampToValueAtTime(880,ctx.currentTime+.12);gain.gain.setValueAtTime(.08,ctx.currentTime);gain.gain.exponentialRampToValueAtTime(.001,ctx.currentTime+.22);osc.start();osc.stop(ctx.currentTime+.23)}catch(e){}}
