  function setLesson(index){const m=moduleById(state.nav.module),lesson=m&&m.lessons[index],access=lesson&&lessonAccessStatus(lesson.id);if(!lessonUnlocked(m,index)){toast(access==='locked'?'This lesson is locked by your teacher.':'This lesson is not available yet.');return}state.nav.lesson=index;state.nav.boss=false;state.nav.tab='overview';state.view='lesson';rememberPage();save();render();scrollToLearningContent()}
