  function pageDescription(page){if(!page||!moduleById(page.module))return 'No study page saved yet';const m=moduleById(page.module),l=m.lessons[Math.min(page.lesson||0,m.lessons.length-1)],labels={overview:'Overview',vocabulary:'Vocabulary',language:'Language Lab',reading:'Reading Summary',practice:'Practice'};return `${m.title} • ${page.boss?'Unit Challenge':l.title+' • '+(labels[page.tab]||'Overview')}`}
