    return `<div class="dashboard-shell"><section class="dashboard-welcome"><div class="dashboard-welcome-content"><div class="dashboard-kicker">Your Personal Learning Dashboard</div><h1>Welcome, ${esc(state.profile.name)}!</h1><p>Explore, learn, practise, and collect rewards. Your English adventure continues from exactly where you stopped.</p><div class="dashboard-progress"><div class="dashboard-progress-top"><span>Course Progress</span><span>${pct}% Complete</span></div><div class="dashboard-progress-track"><span style="width:${pct}%"></span></div></div></div></section><section class="dashboard-metrics"><article class="metric-card"><div class="metric-icon">${uiIcon('book')}</div><strong>${done}/${total}</strong><span>Lessons Completed</span></article><article class="metric-card questions"><div class="metric-icon">${uiIcon('check')}</div><strong>${answered}</strong><span>Questions Answered</span></article><article class="metric-card points"><div class="metric-icon">${uiIcon('bolt')}</div><strong>${state.xp}</strong><span>XP Points • ${state.coins} Coins</span></article><article class="metric-card stars"><div class="metric-icon">${uiIcon('trophy')}</div><strong>${state.stars}</strong><span>Stars • ${units}/${unitModules().length} Units</span></article></section><section class="journey-panel"><div class="journey-head"><div><h2>Continue Your Journey</h2><p>Choose exactly where you want to continue.</p></div><span class="badge">${uiIcon('save')} Auto-saved</span></div><div class="continue-grid"><button type="button" id="resumePageBtn" class="continue-card page" ${lastPage?'':'disabled'}><span class="continue-icon">${uiIcon('book')}</span><strong>Continue Last Page ${uiIcon('arrow')}</strong><span>${lastPage?esc(pageDescription(lastPage)):'Your saved page is not available right now.'}</span></button><button type="button" id="resumeQuestionBtn" class="continue-card question" ${questionResume?'':'disabled'}><span class="continue-icon">${uiIcon('question')}</span><strong>Continue Last Question ${uiIcon('arrow')}</strong><span>${questionResume?`Question ${(questionResume.index||0)+1} • ${esc(pageDescription({...questionResume,tab:'practice'}))}`:'Answer a practice question to activate this button.'}</span></button></div></section><section class="module-gallery"><div class="section-heading"><div><span class="section-kicker">Choose your next adventure</span><h2>Explore All Units</h2></div><span>${shownModules.length} learning journeys</span></div><div class="module-card-grid">${moduleCards}</div></section><div class="dashboard-note">${uiIcon('save')}<span><b>Your progress is safe.</b> The app saves your last page, exact question, answers, XP, coins, and stars automatically.</span></div></div>`
