  function normalizeAnswerText(value,caseSensitive=false,punctuationSensitive=false){let text=String(value||'').trim().replace(/\s+/g,' ');if(!punctuationSensitive)text=text.replace(/[.!?]+$/,'');if(!caseSensitive)text=text.toLowerCase();return text}
