  function recordQuestionResponse(response,m,l,isBoss){const qs=isBoss?bossQuestions(m):lessonQuestions(l),id=isBoss?bossId(m.id):activityId(l.id),a=getActivity(id,qs.length),i=a.index,q=qs[i];if(a.answers[i]!==undefined)return;a.answers[i]=response;a.updatedAt=Date.now();const correct=responseCorrect(response,q);if(correct){a.score++;const rewardKey=`${id}|${q.id}`;if(!state.pointAwards[rewardKey]){state.pointAwards[rewardKey]=true;state.xp+=10;state.coins+=2;a.xpEarned=(a.xpEarned||0)+10;a.coinsEarned=(a.coinsEarned||0)+2}}state.view='lesson';rememberPage();rememberQuestion(m,l,isBoss,i);playTone(correct);save();renderMain();if(correct){flashRewards();toast('Correct! +10 XP and +2 coins');advanceTimer=setTimeout(()=>{const current=state.activities[id];if(current&&!current.completed&&current.index===i)moveQuestion(1,m,l,isBoss)},5000)}}
  function answerQuestion(choice,m,l,isBoss){const qs=isBoss?bossQuestions(m):lessonQuestions(l),id=isBoss?bossId(m.id):activityId(l.id),a=getActivity(id,qs.length),q=qs[a.index];recordQuestionResponse({value:choice,correct:choice===q.answer},m,l,isBoss)}
  function moveQuestion(dir,m,l,isBoss){clearTimeout(advanceTimer);const qs=isBoss?bossQuestions(m):lessonQuestions(l),id=isBoss?bossId(m.id):activityId(l.id),a=getActivity(id,qs.length);if(dir>0&&a.answers[a.index]===undefined)return;if(dir>0&&a.index===qs.length-1){finishActivity(id,m,l,isBoss);return}if(dir>0){const current=qs[a.index],next=qs[a.index+1];if(next&&current.sectionType!==next.sectionType){a.sectionBreak={completedType:current.sectionType,nextType:next.sectionType,nextIndex:a.index+1};a.updatedAt=Date.now();state.view='lesson';rememberPage();save();renderMain();return}}a.sectionBreak=null;a.index=Math.max(0,Math.min(qs.length-1,a.index+dir));a.updatedAt=Date.now();state.view='lesson';rememberPage();rememberQuestion(m,l,isBoss,a.index);save();renderMain()}
  function startNextSection(m,l,isBoss){const qs=isBoss?bossQuestions(m):lessonQuestions(l),id=isBoss?bossId(m.id):activityId(l.id),a=getActivity(id,qs.length),nextIndex=a.sectionBreak&&Number.isFinite(a.sectionBreak.nextIndex)?a.sectionBreak.nextIndex:a.index+1;a.sectionBreak=null;a.index=Math.max(0,Math.min(qs.length-1,nextIndex));a.updatedAt=Date.now();state.view='lesson';rememberPage();rememberQuestion(m,l,isBoss,a.index);save();renderMain();scrollToLearningContent('.section-banner,.question-card')}
  function finishActivity(id,m,l,isBoss){const a=state.activities[id];a.completed=true;a.percent=Math.round(a.score/a.total*100);a.completedAt=Date.now();if(!state.rewards[id]){state.rewards[id]=true;state.xp+=isBoss?100:25;state.coins+=isBoss?50:10;state.stars+=Math.max(1,Math.round(a.percent/34));if(isBoss&&a.percent>=90&&!state.badges.includes(m.id+' Master'))state.badges.push(m.id+' Master')}save();playTone(true);render()}
  function retryActivity(m,l,isBoss){const id=isBoss?bossId(m.id):activityId(l.id),old=state.activities[id]||{};state.activities[id]={index:0,answers:{},score:0,total:isBoss?bossQuestions(m).length:lessonQuestions(l).length,completed:false,sectionBreak:null,percent:0,startedAt:Date.now(),updatedAt:Date.now(),xpEarned:old.xpEarned||0,coinsEarned:old.coinsEarned||0,questionSetVersion:QUESTION_SYSTEM_VERSION};state.view='lesson';rememberPage();state.lastQuestion=null;save();renderMain()}
  function continueJourney(){const units=unitModules(),i=units.findIndex(u=>u.id===state.nav.module),next=units.slice(i+1).find(u=>moduleUnlocked(u.id)&&firstAvailableLessonIndex(u)>=0);if(next)setModule(next.id);else{const reader=moduleById('story');if(reader&&moduleUnlocked('story')&&firstAvailableLessonIndex(reader)>=0)setModule('story');else toast('Excellent work! Choose an unlocked reader from the menu.')}}
  function showCertificate(){const w=window.open('','_blank');w.document.write(`<!doctype html><html><head><title>Certificate</title><style>body{font-family:Trebuchet MS,Arial;text-align:center;padding:40px;color:#17203b}.c{max-width:900px;margin:auto;border:14px double #5b42f3;padding:70px 45px;background:linear-gradient(145deg,#fff,#f5f2ff)}h1{font-size:54px;color:#5b42f3;margin:10px}h2{font-size:34px}.name{font-size:44px;color:#0b8f82;border-bottom:2px solid #0b8f82;display:inline-block;padding:5px 35px}.sig{margin-top:55px;font-weight:bold}@media print{button{display:none}}</style></head><body><div class="c"><div>CONNECT PLUS PRIMARY 4 • TERM 1</div><h1>Certificate of Achievement</h1><p>This certificate is proudly presented to</p><div class="name">${esc(state.profile.name)}</div><h2>Outstanding English Learner</h2><p>for successfully completing the interactive Connect Plus learning journey, including all six units and the fiction reader.</p><p>Class: ${esc(state.profile.className)}</p><div class="sig">Prepared and Designed by: Mr.Mohamed Farid</div><br><button onclick="print()">Print Certificate</button></div></body></html>`);w.document.close()}
  function setStartBusy(busy,mode='signin'){
    const start=$('#startBtn'),create=$('#createAccountBtn'),offline=$('#offlineBtn'),submit=$('#createAccountSubmit'),cancel=$('#cancelCreateAccount');
    [start,create,offline,submit,cancel].forEach(button=>{if(button)button.disabled=busy});
    if(start)start.textContent=busy&&mode==='signin'?'Signing in…':'Sign In →';
    if(create)create.textContent='Create New Account';
    if(submit)submit.textContent=busy&&mode==='create'?'Creating Account…':'Create My Account →';
  }
  function openDestination(destination){rememberAppOpen(true);$('#splash').classList.add('hidden');$('#app').classList.remove('hidden');if(destination==='page'){if(!resumeLastPage())goDashboard();return}if(destination==='question'){if(!resumeLastQuestion())goDashboard();return}state.view='dashboard';save();render()}
  function restoreOpenApp(){if(!wasAppOpen())return false;$('#splash').classList.add('hidden');$('#app').classList.remove('hidden');render();return true}
  function displayNameFromUsername(username){return String(username||'Student').replace(/[_-]+/g,' ').toLowerCase().replace(/(^|\s)([a-z])/g,(m,space,letter)=>space+letter.toUpperCase())}
  function closeCreateAccountModal(){$('#accountModal').classList.add('hidden')}
  function openCreateAccountModal(){
    $('#newStudentCode').value=$('#studentCode').value.trim();
    $('#newStudentClass').value=$('#studentClass').value;
    $('#newStudentPin').value='';
    $('#confirmStudentPin').value='';
    $('#accountModal').classList.remove('hidden');
    setTimeout(()=>($('#newStudentCode').value?$('#newStudentPin'):$('#newStudentCode')).focus(),80);
  }
  async function submitCreateAccount(event){
    if(event)event.preventDefault();
    const studentCode=$('#newStudentCode').value.trim(),className=$('#newStudentClass').value,pin=$('#newStudentPin').value.trim(),confirmPin=$('#confirmStudentPin').value.trim();
    if(!studentCode){toast('Please choose a Username for your new account.');$('#newStudentCode').focus();return}
    if(!className){toast('Please choose your class.');$('#newStudentClass').focus();return}
    if(!/^\d{6}$/.test(pin)){toast('Your PIN must contain exactly 6 numbers.');$('#newStudentPin').focus();return}
    if(pin!==confirmPin){toast('PIN numbers do not match. Please type the same PIN twice.');$('#confirmStudentPin').focus();return}
    setStartBusy(true,'create');
    try{
      if(!window.ConnectCloud||!window.ConnectCloud.available())throw new Error('Cloud connection could not load. Please try again or use This Device Only.');
      const result=await window.ConnectCloud.createStudent({studentCode,pin,name:displayNameFromUsername(studentCode),className});
      cloudUI.signedIn=true;
      state.account={...state.account,studentCode:result.studentCode,cloud:true};
      state.profile={name:result.profile.full_name,className:result.profile.class_name};
      $('#studentCode').value=result.studentCode;
      $('#studentClass').value=result.profile.class_name;
      $('#studentPin').value='';
      closeCreateAccountModal();
      toast('Account created! Your progress will now follow you.');
      openDestination('dashboard');
    }catch(error){
      toast(error&&error.message?error.message:'Could not create the account. Please try again.');
    }finally{
      setStartBusy(false,'create');
    }
  }
  async function startApp(destination='dashboard',offline=false,mode='signin'){
    const className=$('#studentClass').value,studentCode=$('#studentCode').value.trim(),normalizedCode=studentCode.toUpperCase().replace(/\s+/g,''),sameStudent=normalizedCode&&normalizedCode===String(state.account.studentCode||'').toUpperCase();
    const name=sameStudent&&state.profile.name?state.profile.name:displayNameFromUsername(studentCode);
    if(!className){toast('Please choose your class.');return}
    setStartBusy(true,mode);
    try{
      if(!offline){
        if(!window.ConnectCloud||!window.ConnectCloud.available())throw new Error('Cloud connection could not load. Use Continue on This Device Only for now.');
        const pin=$('#studentPin').value.trim();
        const result=await window.ConnectCloud.signInStudent({studentCode,pin,name,className});
        cloudUI.signedIn=true;
        state.account={...state.account,studentCode:result.studentCode,cloud:true};
        state.profile={name:result.profile.full_name,className:result.profile.class_name};
        $('#studentCode').value=result.studentCode;
        $('#studentPin').value='';
      }else{
        state.profile={name,className};
      }
      openDestination(destination);
    }catch(error){
      toast(error&&error.message?error.message:'Could not connect. Please try again.');
    }finally{
      setStartBusy(false,mode);
    }
  }
  async function handleAvatarUpload(event){const file=event.target.files&&event.target.files[0];event.target.value='';if(!file)return;try{toast('Uploading your picture…');await window.ConnectCloud.uploadAvatar(file);toast('Profile picture updated!')}catch(error){toast(error&&error.message?error.message:'Could not upload this picture.')}}
  async function signOutStudent(){rememberAppOpen(false);try{toast('Saving before sign out…');await window.ConnectCloud.signOut()}catch(error){}cloudUI.signedIn=false;$('#studentPin').value='';returnToPortal('signed-out')}
  async function resetStudentProgress(){const profile={...state.profile},account={...state.account};state={...defaultState(),profile,account,view:'dashboard'};localStorage.setItem(APP_KEY,JSON.stringify(state));$('#confirmModal').classList.add('hidden');render();if(window.ConnectCloud&&window.ConnectCloud.isSignedIn())await window.ConnectCloud.syncNow();toast('Student progress has been reset.')}
  async function init(){
    configureCloud();
    fillSplashProfile();
    if(state.profile.name)showResumeMessage();
    $('#startBtn').onclick=()=>startApp('dashboard',false,'signin');
    $('#createAccountBtn').onclick=openCreateAccountModal;
    $('#createAccountForm').onsubmit=submitCreateAccount;
    $('#cancelCreateAccount').onclick=closeCreateAccountModal;
    $('#offlineBtn').onclick=()=>startApp('dashboard',true);
    $('#whoBtn').onclick=()=>$('#profileModal').classList.remove('hidden');
    document.querySelectorAll('[data-close]').forEach(b=>b.onclick=()=>$('#'+b.dataset.close).classList.add('hidden'));
    $('#cancelReset').onclick=()=>$('#confirmModal').classList.add('hidden');
    $('#confirmReset').onclick=resetStudentProgress;
    $('#avatarInput').onchange=handleAvatarUpload;
    $('#menuBtn').onclick=()=>$('#sidebar').classList.toggle('open');
    $('#courseSwitchBtn').onclick=()=>returnToPortal('courses');
    window.addEventListener('online',async()=>{if(window.ConnectCloud){await window.ConnectCloud.refreshAccess();await window.ConnectCloud.syncNow()}});
    window.addEventListener('offline',()=>{cloudUI.status='offline';cloudUI.statusLabel='Saved locally • cloud pending';updateCloudStatus()});
    window.addEventListener('beforeunload',()=>{state.updatedAt=Date.now();localStorage.setItem(APP_KEY,JSON.stringify(state))});
    $('#splash').classList.add('hidden');
    $('#app').classList.add('hidden');
    if(window.ConnectCloud){
      const restored=await window.ConnectCloud.init();
      cloudUI.signedIn=!!restored.signedIn;
      updateCloudStatus();
      if(restored.signedIn){
        rememberAppOpen(true);
        const enteredFromPortal=new URLSearchParams(window.location.search).get('from')==='english-portal';
        if(enteredFromPortal){
          state.view='dashboard';
          state.nav={...defaultState().nav,...state.nav,boss:false};
          save();
        }
        $('#app').classList.remove('hidden');
        render();
        return
      }
    }
    returnToPortal('signin');
  }
  init();
